16	function applyFunctionsUrlOverride<T>(client: T): T {
17	  if (!FUNCTIONS_URL_OVERRIDE) return client;
18	  try {
19	    const c = client as unknown as { functionsUrl?: URL; functions?: { url?: string } };
20	    c.functionsUrl = new URL(FUNCTIONS_URL_OVERRIDE);
21	    if (c.functions) c.functions.url = FUNCTIONS_URL_OVERRIDE;
22	  } catch (err) {
23	    // In coverage mode this MUST work — silent fallback would still
24	    // send requests, but to the real Supabase functions URL, producing
25	    // zero edge coverage that looks like a test problem. Surface it.
26	    if (typeof process !== "undefined" && process.env?.COVERAGE === "1") {
27	      throw new Error(`[coverage] failed to override functions URL: ${err}`);
28	    }
29	    if (typeof console !== "undefined") {
30	      console.warn("[coverage] failed to override functions URL:", err);
